def gen(rng, size):
    alphabet = 'abc'
    length_cap = max(1, min(size, 100))
    def rand_str():
        length = rng.randint(1, length_cap)
        return ''.join(rng.choice(alphabet) for _ in range(length))
    return [rand_str(), rand_str(), rand_str()]

