class Solution:
    def minimumString(self, a, b, c):
        import itertools

        def kmp_overlap(x, y):
            combined = y + '#' + x
            n = len(combined)
            fail = [0] * n
            for i in range(1, n):
                j = fail[i - 1]
                while j > 0 and combined[i] != combined[j]:
                    j = fail[j - 1]
                if combined[i] == combined[j]:
                    j += 1
                fail[i] = j
            return fail[-1]

        def merge2(x, y):
            if y in x:
                return x
            if x in y:
                return y
            ov = kmp_overlap(x, y)
            return x + y[ov:]

        best = None
        for perm in itertools.permutations([a, b, c]):
            merged = merge2(merge2(perm[0], perm[1]), perm[2])
            if best is None or len(merged) < len(best) or (len(merged) == len(best) and merged < best):
                best = merged
        return best

