class Solution:
    def minimumString(self, a, b, c):
        import itertools

        def merge2(x, y):
            if y in x:
                return x
            if x in y:
                return y
            max_ov = 0
            for k in range(min(len(x), len(y)), 0, -1):
                if x[-k:] == y[:k]:
                    max_ov = k
                    break
            return x + y[max_ov:]

        best = None
        for perm in itertools.permutations([a, b, c]):
            merged = merge2(merge2(perm[0], perm[1]), perm[2])
            if best is None or len(merged) < len(best) or (len(merged) == len(best) and merged < best):
                best = merged
        return best

