var minimumString = function(a, b, c) {
    function merge2(x, y) {
        if (x.includes(y)) return x;
        if (y.includes(x)) return y;
        let maxOv = 0;
        for (let k = Math.min(x.length, y.length); k > 0; k--) {
            if (x.slice(-k) === y.slice(0, k)) {
                maxOv = k;
                break;
            }
        }
        return x + y.slice(maxOv);
    }

    function permutations(arr) {
        if (arr.length <= 1) return [arr];
        const result = [];
        for (let i = 0; i < arr.length; i++) {
            const rest = arr.slice(0, i).concat(arr.slice(i + 1));
            for (const p of permutations(rest)) {
                result.push([arr[i], ...p]);
            }
        }
        return result;
    }

    let best = null;
    for (const perm of permutations([a, b, c])) {
        const merged = merge2(merge2(perm[0], perm[1]), perm[2]);
        if (best === null || merged.length < best.length || (merged.length === best.length && merged < best)) {
            best = merged;
        }
    }
    return best;
};
